    end_date: string
    id: string
    stage: string
    start_date: string
  } | null
  channel: GraphQLChannel
  id: string
  listing: {
    id: string
    name: string
  } | null
  messages: Array<{
    guest: GraphQLPerson | null
    guest_id: string | null
    id: string
